import React from "react";
import Alpha from "../../../assets/images/DashboardImgs/alpha.png";
import Eye from "../../../assets/images/DashboardImgs/eye.png";
import Edit from "../../../assets/images/DashboardImgs/edit.png";
import Clip2 from "../../../assets/images/DashboardImgs/clipboard-list2.png";
import Pagination from "react-js-pagination";
import { Link } from "react-router-dom";



class MenteeJobLists extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
            errors: {},
            postCount: 0
        };
    }
    PostsDetails() {
        if (this.props.jobLists && this.props?.jobLists?.data?.length > 0) {
            let applied = false
            return this.props.jobLists.data.map((element, index) => {
                // x => x.post_id === element.id
                applied = this.props?.appliedJobs?.filter(el=> el.post_id == element.id)
                let checked = false;
                if (this.props?.selected) {
                    let s_i = this.props.selected.findIndex(x => x == index);
                    if (s_i !== -1) {
                        checked = true;
                    }
                }
                return (
                    <div className="row mar-width-0 ActivePosts" key={element.id}>
                        <div className="col-md-2 d-flex text-center align-self-center align-items-center">
                            <img src={Alpha} className="Profile-icon-" alt="" />
                        </div>
                        <div className="col-md-8 ActivePosts_ align-self-center">
                            <h6>{element.job_title} - {element.city.name}, {element.country.name}  <Link to={`/ViewPost/${element.id}`}><img src={Eye} className="profile-icon-" alt="" /></Link> <span className="color-">Oct 22, 2021</span> </h6>
                            <p>Offered Salary: {element.details.start_price}k - {element.details.end_price}k &nbsp; Post By: {element.user.first_name} {element.user.last_name}</p>
                            <p className="font-weight-500">   <img src={Eye} className="profile-icon-" alt="" /> Reviewed: 60 &nbsp; <span className="color--">|</span> &nbsp; <img src={Clip2} className="profile-icon-" alt="" /> Shortlisted: 5</p>
                        </div>
                        <div className="col-md-2 text-right pt-3 m-auto">
                            {this.appliedStatus(applied,element.id)}
                        </div>
                    </div>
                )
            })
        } else {
            return (
                <div className="row mar-width-0 ActivePosts">
                    <div className="col-md-12 d-flex mt-4 no-post-data">
                        <p>No Post Data found</p>
                    </div>
                </div>
            )
        }
    }
    appliedStatus = (val,id) =>{
        if(val.length){
            return(
                <button className="btn apply-btn btn-applied">Applied</button>
            )
        }else{
            return(
                <button className="btn apply-btn" onClick={() => this.props?.jobApplied(id)}>Apply</button>
            )
        }
    } 
    postStatus = (val) => {
        switch (val.status) {
            case 0:
                return (
                    <span className="inactive-span">  Inactive</span>
                )
            case 1:
                return (
                    <span className="active-span">  Active</span>
                )
            case 2:
                return (
                    <span className="feature-span">  Featured</span>
                )
        }
    }

    postPagination = () => {
        if (this.props?.pagination) {
            return (
                <Pagination
                    activePage={this.props?.jobLists?.current_page ? this.props?.jobLists?.current_page : 0}
                    itemsCountPerPage={this.props?.jobLists?.per_page ? this.props?.jobLists?.per_page : 0}
                    totalItemsCount={this.props?.jobLists?.total ? this.props?.jobLists?.total : 0}
                    onChange={(pageNumber) => {
                        this.props.pageHandler(pageNumber)
                    }}
                    pageRangeDisplayed={10}
                    itemClass="page-item"
                    linkClass="page-link"
                    firstPageText="First Page"
                    lastPageText="Last Page"
                    className="pagination"
                />
            )
        }
    }

    render() {
        return (
            <>
                <div className={this.props?.className}>
                    {
                        this.PostsDetails()
                    }
                </div>

                <div>
                    {this.postPagination()}
                </div>
            </>
        );
    }
}

export default MenteeJobLists;